const siteConfig = $('Site Config').first().json;
const defaultLang = siteConfig.translation?.default_language || siteConfig.n8npress?.target_language || 'en';
const activeLangs = siteConfig.translation?.active_languages || [];
const targetLangs = activeLangs.filter(l => l !== defaultLang);
const defaultLanguages = targetLangs.length > 0 ? targetLangs : ['en'];

let webhookData = null;
try { webhookData = $('Translation Request Webhook').first()?.json; } catch(e) {}
const body = webhookData?.body || webhookData || {};

// Taxonomy translation request
if (body.event === 'taxonomy_translation_request') {
  let langs = defaultLanguages;
  if (body.target_languages) {
    langs = Array.isArray(body.target_languages) ? body.target_languages : body.target_languages.split(',').map(l => l.trim());
  }
  return [{ json: {
    mode: 'taxonomy',
    taxonomy: body.taxonomy || 'product_cat',
    target_languages: langs,
    default_language: defaultLang,
    source_language: body.source_language || defaultLang,
    callback_url: body.callback_url || '',
    api_token: body.api_token || siteConfig.n8npress?.api_token || '',
    site_url: body.site_url || siteConfig.site?.url || '',
    fetch_endpoint: body.fetch_endpoint || '',
    _ai_api_key: siteConfig.n8npress?.ai?.openai_key || siteConfig.n8npress?.ai?.api_key || $env.OPENAI_API_KEY || '',
    _ai_model: siteConfig.n8npress?.ai?.model || 'gpt-4o-mini'
  } }];
}

// Product/content translation
const isSingleProduct = !!body.product_id && body.event !== 'translate_missing';
const isBatchRequest = body.event === 'translate_missing' || !!body.fetch_pending;

let langs = defaultLanguages;
if (body.target_languages) {
  langs = Array.isArray(body.target_languages) ? body.target_languages : body.target_languages.split(',').map(l => l.trim());
}

if (isSingleProduct) {
  return [{ json: { mode: 'product', product_ids: [body.product_id], target_languages: langs, default_language: defaultLang, source: 'webhook' } }];
}
if (isBatchRequest) {
  return [{ json: { mode: 'product', product_ids: [], target_languages: langs, default_language: defaultLang, post_type: body.post_type || 'product', limit: body.limit || 10, source: 'batch_webhook', fetch_pending: true } }];
}
return [{ json: { mode: 'product', product_ids: [], target_languages: defaultLanguages, default_language: defaultLang, source: 'schedule', fetch_pending: true } }];

const source = $('Is Taxonomy?').first().json;
const response = $input.first().json;
const terms = response.terms || [];

if (terms.length === 0) {
  return [{ json: { skip: true, message: 'No terms to translate' } }];
}

// Build AI prompt for all terms in one batch per language
const sourceLang = source.source_language || source.default_language || 'en';
const taxonomy = source.taxonomy || 'product_cat';
const allLangs = new Set();
for (const term of terms) {
  for (const lang of (term.missing_languages || [])) {
    allLangs.add(lang);
  }
}

const results = [];
for (const lang of allLangs) {
  const termsForLang = terms.filter(t => (t.missing_languages || []).includes(lang));
  if (termsForLang.length === 0) continue;

  const termList = termsForLang.map(t => `- term_id: ${t.term_id}, name: "${t.name}", slug: "${t.slug}"`).join('\n');

  const prompt = `Translate the following ${taxonomy === 'product_cat' ? 'product category' : 'product tag'} names from ${sourceLang} to ${lang}.\n\nTerms:\n${termList}\n\nRULES:\n- Keep brand names as-is\n- Create SEO-friendly slugs (lowercase, hyphens, no special chars)\n- Return ONLY valid JSON array\n\nRespond with:\n[{"term_id": 123, "name": "translated name", "slug": "translated-slug", "language": "${lang}"}]`;

  const body = JSON.stringify({
    model: source._ai_model || 'gpt-4o-mini',
    max_tokens: 2000,
    messages: [{ role: 'user', content: prompt }]
  });

  results.push({ json: {
    _ai_body: body,
    _ai_api_key: source._ai_api_key,
    _callback_url: source.callback_url || (source.site_url + '/wp-json/n8npress/v1/translation/taxonomy-callback'),
    _api_token: source.api_token,
    _site_url: source.site_url,
    _taxonomy: taxonomy,
    _language: lang,
    _term_count: termsForLang.length
  } });
}

if (results.length === 0) {
  return [{ json: { skip: true, message: 'No terms need translation' } }];
}

return results;

const promptItems = $('Has Terms?').all();
const aiResponses = $input.all();

const allTranslations = [];

for (let i = 0; i < aiResponses.length; i++) {
  const ctx = promptItems[i]?.json || {};
  const response = aiResponses[i].json;
  const rawContent = response.choices?.[0]?.message?.content || '[]';

  let translations;
  try {
    translations = JSON.parse(rawContent);
  } catch(e) {
    const match = rawContent.match(/\[\s*\{[\s\S]*\}\s*\]/);
    try { translations = match ? JSON.parse(match[0]) : []; } catch(e2) { translations = []; }
  }

  if (Array.isArray(translations)) {
    for (const t of translations) {
      allTranslations.push({
        term_id: t.term_id,
        name: t.name || '',
        slug: t.slug || '',
        language: t.language || ctx._language || ''
      });
    }
  }
}

if (allTranslations.length === 0) {
  return [{ json: { skip: true, message: 'AI returned no translations' } }];
}

// Use first context for callback info
const ctx = promptItems[0]?.json || {};

return [{ json: {
  _callback_body: JSON.stringify({
    taxonomy: ctx._taxonomy,
    translations: allTranslations
  }),
  _callback_url: ctx._callback_url,
  _taxonomy: ctx._taxonomy,
  _count: allTranslations.length
} }];

const sourceData = $('Is Taxonomy?').first().json;
const siteConfig = $('Site Config').first().json;
const response = $input.first().json;

const siteUrl = siteConfig.site?.url || siteConfig.site?.home_url || '';
const apiToken = siteConfig.n8npress?.api_token || '';
const aiApiKey = siteConfig.n8npress?.ai?.api_key || '';
const aiModel = siteConfig.n8npress?.ai?.model || 'gpt-4o-mini';
const aiMaxTokens = siteConfig.n8npress?.ai?.max_tokens || 3000;
const defaultLang = sourceData.default_language || 'en';

// Use missing-all response: each product has missing_languages array
const products = response.products || [];
const items = [];

for (const p of products) {
  const productId = p.product_id || p.id;
  const missingLangs = p.missing_languages || sourceData.target_languages || [];
  for (const lang of missingLangs) {
    items.push({ json: { product_id: productId, target_language: lang, default_language: defaultLang, _site_url: siteUrl, _api_token: apiToken, _ai_api_key: aiApiKey, _ai_model: aiModel, _ai_max_tokens: aiMaxTokens } });
  }
}

if (items.length === 0) {
  return [{ json: { skip: true, message: 'No products to translate' } }];
}

return items;

// Match products by ID (not index) to avoid order mismatch
const matrixItems = $('Has Products?').all();
const products = $input.all();

// Build lookup: product_id -> matrix context
const ctxMap = {};
for (const m of matrixItems) {
  ctxMap[m.json.product_id] = m.json;
}

const results = [];
for (let i = 0; i < products.length; i++) {
  const product = products[i].json;
  const productWpId = product.id;
  const ctx = ctxMap[productWpId] || matrixItems[i]?.json || matrixItems[0]?.json || {};

  const productName = product.title?.rendered || product.name || '';
  const productDesc = product.content?.rendered || product.description || '';
  const shortDesc = product.excerpt?.rendered || product.short_description || '';
  const meta = product.meta || {};
  const metaArr = product.meta_data || [];
  const metaTitle = meta.rank_math_title || (metaArr.find && metaArr.find(m => m.key === 'rank_math_title')?.value) || productName;
  const metaDesc = meta.rank_math_description || (metaArr.find && metaArr.find(m => m.key === 'rank_math_description')?.value) || '';
  const focusKw = meta.rank_math_focus_keyword || (metaArr.find && metaArr.find(m => m.key === 'rank_math_focus_keyword')?.value) || '';

  const prompt = `You are an expert SEO-aware translator for e-commerce. Translate the following product from ${ctx.default_language || 'en'} to ${ctx.target_language || 'fr'}.\n\nRULES: Preserve brand names as-is. Meta title <60 chars. Meta description <160 chars. Natural language. Preserve HTML.\n\nProduct ID: ${ctx.product_id}\nTarget Language: ${ctx.target_language}\nTitle: ${productName}\nDescription: ${productDesc}\nShort Description: ${shortDesc}\nMeta Title: ${metaTitle}\nMeta Description: ${metaDesc}\nFocus Keyword: ${focusKw}\n\nRespond ONLY with valid JSON:\n{"product_id": ${ctx.product_id}, "target_language": "${ctx.target_language}", "title": "", "description": "", "short_description": "", "meta_title": "", "meta_description": "", "focus_keyword": "", "slug": ""}`;

  const contentLen = productDesc.length + shortDesc.length;
  const maxTokens = contentLen > 3000 ? 8000 : (ctx._ai_max_tokens || 4000);
  const body = JSON.stringify({ model: ctx._ai_model || 'gpt-4o-mini', max_tokens: maxTokens, messages: [{ role: 'user', content: prompt }] });

  results.push({ json: { _product_id: ctx.product_id, _target_language: ctx.target_language, _site_url: ctx._site_url, _api_token: ctx._api_token, _ai_api_key: ctx._ai_api_key, _ai_body: body, product_name: productName } });
}

return results;

const enrichItems = $('Enrich Product Data').all();
const aiResponses = $input.all();

const ctxMap = {};
for (const e of enrichItems) {
  ctxMap[e.json._product_id] = e.json;
}

const results = [];
for (let i = 0; i < aiResponses.length; i++) {
  const response = aiResponses[i].json;
  const rawContent = response.choices?.[0]?.message?.content || '{}';
  let translated;
  try {
    translated = JSON.parse(rawContent);
  } catch(e) {
    const match = rawContent.match(/```(?:json)?\s*([\s\S]*?)```/) || rawContent.match(/\{[\s\S]*\}/);
    try { translated = match ? JSON.parse(match[1] || match[0]) : null; } catch(e2) { translated = null; }
  }

  const aiPid = translated?.product_id;
  const ctx = ctxMap[aiPid] || enrichItems[i]?.json || enrichItems[0]?.json || {};

  if (!translated) {
    results.push({ json: { _callback_body: JSON.stringify({product_id: ctx._product_id, language: ctx._target_language, content: {name:'',description:'',short_description:'',meta_title:'',meta_description:'',focus_keyword:'',slug:''}, status: 'error'}), _callback_url: ctx._site_url + '/wp-json/n8npress/v1/translation/callback' } });
    continue;
  }

  const callbackPayload = {
    product_id: ctx._product_id || translated.product_id,
    language: ctx._target_language || translated.target_language,
    content: {
      name: translated.title || translated.name || '',
      description: translated.description || '',
      short_description: translated.short_description || '',
      meta_title: translated.meta_title || '',
      meta_description: translated.meta_description || '',
      focus_keyword: translated.focus_keyword || '',
      slug: translated.slug || ''
    },
    status: 'completed'
  };

  results.push({ json: { _callback_body: JSON.stringify(callbackPayload), _callback_url: ctx._site_url + '/wp-json/n8npress/v1/translation/callback', product_name: ctx.product_name, product_id: ctx._product_id || translated.product_id, target_language: ctx._target_language || translated.target_language } });
}

return results;
